    // Create a binary_stream using the buffer_adaptor
    hexi::binary_stream<decltype(adaptor)> stream(adaptor);

    // Write the header (uint16_t) using operator<<
    stream << packet.header;

    // Write the data string with prefix using operator<<
    stream << packet.data;

    // Write 16 bytes of padding (0x00) using fill<16>(0x00)
    stream.fill<16>(0x00);

    // Write the footer (uint32_t) using operator<<
    stream << packet.footer;

    // Return the populated buffer
    return buffer;
}
